18	/// Shared handle passed to the control listener and polled by tray/UI.
19	///
20	/// All fields are cheap to clone (Arc-wrapped).
21	#[derive(Clone)]
22	pub struct DaemonHandle {
23	    /// Macro dispatcher shared with the pipeline; used to push profile updates.
24	    pub dispatcher: Arc<Dispatcher>,
25	    /// Set true to suppress audio processing. The pipeline thread checks this
26	    /// on each frame and skips wake/VAD/STT while muted.
27	    pub muted: Arc<AtomicBool>,
28	    /// Name of the currently active profile, updated on every SwitchProfile.
29	    pub active_profile: Arc<RwLock<Option<String>>>,
30	    /// Set true while the wake-word listen window is open (written by coordinator).
31	    pub listening: Arc<AtomicBool>,
32	    /// Set true while PTT is held (written by coordinator).
33	    pub recording: Arc<AtomicBool>,
34	    /// Channel to the running pipeline coordinator for live runtime changes.
35	    /// `None` when the pipeline is not running (e.g. during unit tests).
36	    pub runtime_cmd_tx: Option<Arc<std::sync::mpsc::Sender<RuntimeCommand>>>,
37	    /// Currently cached activation mode; updated by the SetMode handler before
38	    /// forwarding to the coordinator so Status responses stay coherent.
39	    pub active_mode: Arc<RwLock<ActivationMode>>,
40	}
41	
42	impl DaemonHandle {
43	    /// Create a new handle wrapping the given dispatcher with all state flags initialised to false/None.
44	    pub fn new(dispatcher: Arc<Dispatcher>) -> Self {
45	        Self {
46	            dispatcher,
47	            muted: Arc::new(AtomicBool::new(false)),
48	            active_profile: Arc::new(RwLock::new(None)),
49	            listening: Arc::new(AtomicBool::new(false)),
50	            recording: Arc::new(AtomicBool::new(false)),
51	            runtime_cmd_tx: None,
52	            active_mode: Arc::new(RwLock::new(ActivationMode::Ptt)),
53	        }
54	    }
55	
56	    /// Attach the runtime command sender produced by `spawn_pipeline`.
57	    pub fn with_runtime_tx(mut self, tx: std::sync::mpsc::Sender<RuntimeCommand>) -> Self {
58	        self.runtime_cmd_tx = Some(Arc::new(tx));
59	        self
60	    }
61	
62	    /// Send a [`RuntimeCommand`] to the pipeline coordinator.
63	    ///
64	    /// Returns `ControlResponse::Ok` on success or
65	    /// `ControlResponse::Error { message }` when the pipeline is not running.
66	    fn send_runtime_cmd(&self, cmd: RuntimeCommand) -> ControlResponse {
67	        match &self.runtime_cmd_tx {
68	            Some(tx) => match tx.send(cmd) {
69	                Ok(()) => ControlResponse::Ok,
70	                Err(_) => ControlResponse::Error { message: "pipeline not running".into() },
71	            },
72	            None => ControlResponse::Error { message: "pipeline not running".into() },
73	        }
74	    }
75	
76	    /// Derive the current [`DaemonState`] from the atomic flags, in priority order: Muted > Recording > Listening > Idle.
77	    pub fn state(&self) -> DaemonState {
78	        if self.muted.load(Ordering::Relaxed) {
79	            DaemonState::Muted
80	        } else if self.recording.load(Ordering::Relaxed) {
81	            DaemonState::Recording
82	        } else if self.listening.load(Ordering::Relaxed) {
83	            DaemonState::Listening
84	        } else {
85	            DaemonState::Idle
86	        }
87	    }
88	
89	    /// Build a full [`DaemonStatus`] snapshot (state + active profile + macro count + active mode) for Status queries.
90	    pub fn status(&self) -> DaemonStatus {
91	        let macro_count = self.dispatcher.macro_count();
92	        DaemonStatus {
93	            state: self.state(),
94	            active_profile: self.active_profile.read().unwrap().clone(),
95	            macro_count,
96	            active_mode: self.active_mode.read().unwrap().clone(),
97	        }
98	    }
99	}
