28	impl DispatcherState {
29	    pub(crate) fn new() -> Self {
30	        Self {
31	            flags: Arc::new(RwLock::new(HashMap::new())),
32	        }
33	    }
34	
35	    pub(crate) fn get(&self, flag: &str) -> bool {
36	        *self.flags.read().unwrap().get(flag).unwrap_or(&false)
37	    }
38	
39	    pub(crate) fn set(&self, flag: &str, value: bool) {
40	        self.flags.write().unwrap().insert(flag.to_string(), value);
41	    }
